import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import "./ClientDashboard.css";

function ClientDashboard() {
  const [stats, setStats] = useState({
    inProgress: 0,
    newProposals: 0,
    totalProjects: 0
  });
  const [projects, setProjects] = useState([]);
  const [proposals, setProposals] = useState([]);
  const [unreadNotifications] = useState(2);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("access");
    if (!token) {
      navigate("/");
    } else {
      fetchDashboardData();
    }
  }, [navigate]);

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('access');
      
      // Get current user info
      const userRes = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      const currentUser = userRes.data;
      
      // Fetch all projects
      const projectsRes = await axios.get('http://127.0.0.1:8000/api/projects/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      // Fetch all proposals
      const proposalsRes = await axios.get('http://127.0.0.1:8000/api/proposals/', {
        headers: { Authorization: `Bearer ${token}` }
      });

      // Filter client's own projects
      const clientProjects = projectsRes.data.filter(p => p.client === currentUser.id);
      
      // Filter proposals for client's projects
      const clientProjectIds = clientProjects.map(p => p.id);
      const clientProposals = proposalsRes.data.filter(p => clientProjectIds.includes(p.project));
      const newProps = clientProposals.filter(p => p.status === 'pending');
      
      setProjects(clientProjects.slice(0, 2)); // Show only 2
      setProposals(newProps.slice(0, 3)); // Show only 3
      setStats({
        inProgress: clientProjects.filter(p => p.status === 'in_progress').length,
        newProposals: newProps.length,
        totalProjects: clientProjects.length
      });
      
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  return (
    <div className="dashboard-container">
      {/* Top Bar */}
      <div className="top-bar">
        <div className="logo">🔷 TalentLink</div>
        <div className="user-menu">
          <span className="notification-badge">🔔 {unreadNotifications}</span>
          <span className="profile-dropdown">👤 Client ▼</span>
          <button onClick={handleLogout} className="logout-btn">🚪</button>
        </div>
      </div>

      {/* Welcome Section */}
      <div className="welcome-section">
        <h2>👋 Welcome back, Client!</h2>
        <span className="date">{new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</span>
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <span className="stat-label">📊 In Progress Projects</span>
          <span className="stat-value">{stats.inProgress}</span>
        </div>
        <div className="stat-card highlight">
          <span className="stat-label">✨ New Proposals</span>
          <span className="stat-value">{stats.newProposals}</span>
        </div>
        <div className="stat-card">
          <span className="stat-label">📁 Total Projects</span>
          <span className="stat-value">{stats.totalProjects}</span>
        </div>
      </div>

      {/* Post New Project CTA */}
      <button className="post-project-btn" onClick={() => navigate('/projects/create')}>
        ➕ POST NEW PROJECT
      </button>

      {/* My Projects Section */}
      <div className="section-header">
        <h3>📁 MY PROJECTS</h3>
        <button className="view-all" onClick={() => navigate('/projects')}>View All →</button>
      </div>
      <div className="projects-list">
        {projects.length > 0 ? (
          projects.map(project => (
            <div key={project.id} className="project-item">
              <div className="project-info">
                <strong>{project.title}</strong>
                <div className="project-meta">
                  📅 {new Date(project.created_at).toLocaleDateString()} | 💰 ₹{project.budget_min}-{project.budget_max}
                </div>
              </div>
              <div className="project-actions">
                <button onClick={() => navigate(`/projects/${project.id}`)}>View</button>
                <button onClick={() => navigate(`/projects/edit/${project.id}`)}>Edit</button>
                <button onClick={() => navigate(`/projects/${project.id}/proposals`)}>See Proposals</button>
              </div>
            </div>
          ))
        ) : (
          <p className="no-data">No projects yet. Create your first project!</p>
        )}
      </div>

      {/* New Proposals Section */}
      <div className="section-header">
        <h3>✨ NEW PROPOSALS ({stats.newProposals})</h3>
        <button className="view-all" onClick={() => navigate('/proposals')}>View All →</button>
      </div>
      <div className="proposals-list">
        {proposals.length > 0 ? (
          proposals.map(proposal => (
            <div key={proposal.id} className="proposal-item">
              <div className="proposal-info">
                <strong>👤 {proposal.freelancer_name} (⭐ 4.8)</strong>
                <div>📝 {proposal.project_title}</div>
                <div className="proposal-meta">
                  💰 Bid: ₹{proposal.bid_amount} | ⏱️ {proposal.estimated_days} days
                </div>
              </div>
              <div className="proposal-actions">
                <button className="accept-btn">Accept</button>
                <button className="reject-btn">Reject</button>
                <button onClick={() => navigate(`/freelancer/${proposal.freelancer}`)}>View Profile</button>
              </div>
            </div>
          ))
        ) : (
          <p className="no-data">No new proposals yet.</p>
        )}
      </div>

      {/* Active Contracts Section */}
      <div className="section-header">
        <h3>✅ ACTIVE CONTRACTS</h3>
        <button className="view-all" onClick={() => navigate('/contracts')}>View All →</button>
      </div>
      <div className="contracts-list">
        <div className="contract-item">
          <div className="contract-info">
            <strong>👤 Freelancer Name</strong> → <span>Project Title</span>
            <div className="contract-meta">
              🟢 In Progress | Started: Feb 15, 2026
            </div>
          </div>
          <div className="contract-actions">
            <button onClick={() => navigate('/messages')}>Message</button>
            <button onClick={() => navigate('/contracts/1')}>View Contract</button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ClientDashboard;
